import { useMemo, useState } from 'react';
import Product from '../components/Product';
import books from '../product_list';

const HomeScreen = () => {
  const [category, setCategory] = useState('Sve');
  const [query, setQuery] = useState('');

  const categories = ['Sve', ...new Set(books.map((book) => book.category))];
  const filteredBooks = useMemo(
    () =>
      books.filter((book) => {
        const byCategory = category === 'Sve' || book.category === category;
        const byQuery = `${book.name} ${book.author} ${book.city}`.toLowerCase().includes(query.toLowerCase());
        return byCategory && byQuery;
      }),
    [category, query],
  );

  return (
    <>
      <section className="hero">
        <div>
          <h1>Pronadji knjigu koja je vec prosla kroz necije omiljene stranice.</h1>
        </div>
      </section>

      <div className="toolbar">
        <h2>Nove knjige</h2>
        <div className="filters-row">
          <input
            type="search"
            placeholder="Pretraga knjiga"
            value={query}
            onChange={(event) => setQuery(event.target.value)}
          />
          <select value={category} onChange={(event) => setCategory(event.target.value)}>
            {categories.map((item) => (
              <option key={item}>{item}</option>
            ))}
          </select>
        </div>
      </div>

      <section className="product-grid">
        {filteredBooks.map((book) => (
          <Product book={book} key={book.id} />
        ))}
      </section>
    </>
  );
};

export default HomeScreen;
